{"cmd":"cat > /app/solution.sparql <<'EOF'
PREFIX uni: <http://university.org/ontology/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?professorName (GROUP_CONCAT(DISTINCT ?country; separator=", ") AS ?countries)
WHERE {
  ?professor a uni:Person ;
             uni:hasName ?professorName ;
             uni:role ?role ;
             uni:worksIn ?dept .

  # Full professors only (exclude Assistant/Associate-style roles).
  FILTER(STRSTARTS(?role, "Professor"))

  ?dept uni:belongsTo ?university .
  ?university uni:locatedInCountry ?country .

  # Must work in at least one department in an EU country (as of 2025-08-16).
  FILTER EXISTS {
    ?professor uni:worksIn ?euDept .
    ?euDept uni:belongsTo ?euUniversity .
    ?euUniversity uni:locatedInCountry ?euCountry .
    FILTER(
